// src/components/Hero.jsx
// ─────────────────────────────────────────────
// INSTRUCCIONES PARA EL VÍDEO:
// 1. Copia tu vídeo a la carpeta /public del proyecto
// 2. Renómbralo a: hero-video.mp4
// 3. Listo — aparecerá automáticamente dentro del círculo
// ─────────────────────────────────────────────

import { personal } from '../data/portfolio';

export default function Hero() {
  return (
    <section id="hero" style={s.section}>
      {/* Grid de fondo */}
      <div style={s.bgGrid} />
      {/* Glow rojo de fondo */}
      <div style={s.bgGlow} />

      {/* ── Contenido principal ── */}
      <div style={s.content}>

        <div style={s.badge}>
          <span style={s.badgeDot} />
          Available for work
        </div>

        <p style={s.greeting}>Hello, I'm</p>

        <h1 style={s.name}>
          {personal.name.split(' ')[0]}<br />
          <span style={s.nameAccent}>{personal.name.split(' ')[1]}</span>
        </h1>

        <p style={s.role}>{personal.role}</p>
        <p style={s.tagline}>{personal.tagline}</p>

        <p style={s.desc}>
          Desarrollador Web proactivo con experiencia práctica en
          aplicaciones Full Stack en entornos reales. Especializado en{' '}
          <strong style={s.strong}>React</strong>,{' '}
          <strong style={s.strong}>.NET</strong> y{' '}
          <strong style={s.strong}>SQL</strong>.
          Alta capacidad de adaptación y aprendizaje rápido.
        </p>

        <div style={s.actions}>
          <a
            href="#contact"
            style={s.btnPrimary}
            onMouseEnter={e => {
              e.currentTarget.style.background = 'var(--accent2)';
              e.currentTarget.style.transform = 'translateY(-2px)';
            }}
            onMouseLeave={e => {
              e.currentTarget.style.background = 'var(--accent)';
              e.currentTarget.style.transform = 'none';
            }}
          >
            Get in touch
          </a>
          <a
            href="#experience"
            style={s.btnSecondary}
            onMouseEnter={e => {
              e.currentTarget.style.borderColor = 'rgba(255,255,255,0.3)';
              e.currentTarget.style.transform = 'translateY(-2px)';
            }}
            onMouseLeave={e => {
              e.currentTarget.style.borderColor = 'var(--border2)';
              e.currentTarget.style.transform = 'none';
            }}
          >
            View my work ↓
          </a>
        </div>

        {/* Stats */}
        <div style={s.stats}>
          {personal.stats.map((st, i) => (
            <div key={i} style={s.stat}>
              <div style={s.statNum}>
                {st.value.replace(/[^0-9A-Za-z]/g, '')}
                <span style={s.statAccent}>
                  {st.value.match(/[^0-9A-Za-z]/)?.[0] || ''}
                </span>
              </div>
              <div style={s.statLabel}>{st.label}</div>
            </div>
          ))}
        </div>
      </div>

      {/* ── Círculo con vídeo ── */}
      <div style={s.mediaWrap}>
        {/* Anillo exterior giratorio */}
        <div style={s.ringOuter}>
          {/* Puntos decorativos en el anillo */}
          {[0, 60, 120, 180, 240, 300].map(deg => (
            <div
              key={deg}
              style={{
                ...s.ringDot,
                transform: `rotate(${deg}deg) translateX(159px)`,
              }}
            />
          ))}
        </div>

        {/* Anillo interior estático */}
        <div style={s.ringInner} />

        {/* Círculo con vídeo / fallback */}
        <div style={s.videoCircle}>
          <video
            autoPlay
            loop
            muted
            playsInline
            style={s.video}
            onError={e => {
              // Si no encuentra el vídeo, muestra el fallback
              e.currentTarget.style.display = 'none';
              e.currentTarget.nextSibling.style.display = 'flex';
            }}
          >
            <source src="/hero-video.mp4" type="video/mp4" />
          </video>

          {/* Fallback: iniciales (se oculta cuando hay vídeo) */}
          <div style={s.fallback}>
            <span style={s.fallbackText}>RM</span>
          </div>
        </div>

        {/* Puntos flotantes decorativos */}
        <div style={{ ...s.floatDot, top: '8%',  right: '-10%', width: 10, height: 10 }} />
        <div style={{ ...s.floatDot, bottom: '18%', left: '-8%',  width: 6,  height: 6,  opacity: 0.3 }} />
        <div style={{ ...s.floatDot, top: '55%', right: '-14%', width: 5,  height: 5,  opacity: 0.2 }} />
      </div>
    </section>
  );
}

const s = {
  section: {
    minHeight: '100vh',
    display: 'flex',
    alignItems: 'center',
    padding: '120px 5% 80px',
    position: 'relative',
    overflow: 'hidden',
  },

  bgGrid: {
    position: 'absolute', inset: 0,
    backgroundImage: `
      linear-gradient(rgba(255,255,255,0.018) 1px, transparent 1px),
      linear-gradient(90deg, rgba(255,255,255,0.018) 1px, transparent 1px)
    `,
    backgroundSize: '56px 56px',
    pointerEvents: 'none',
  },

  bgGlow: {
    position: 'absolute',
    right: '-4%', top: '50%',
    transform: 'translateY(-50%)',
    width: 700, height: 700,
    borderRadius: '50%',
    background: 'radial-gradient(circle, rgba(232,58,58,0.14) 0%, rgba(232,58,58,0.03) 55%, transparent 70%)',
    pointerEvents: 'none',
  },

  content: {
    position: 'relative',
    zIndex: 2,
    maxWidth: 640,
  },

  badge: {
    display: 'inline-flex', alignItems: 'center', gap: 8,
    background: 'rgba(232,58,58,0.09)',
    border: '1px solid rgba(232,58,58,0.22)',
    color: 'var(--accent2)',
    fontSize: 11, fontWeight: 600,
    letterSpacing: '0.12em', textTransform: 'uppercase',
    padding: '6px 16px', borderRadius: 100,
    marginBottom: 32,
  },
  badgeDot: {
    display: 'inline-block',
    width: 6, height: 6, borderRadius: '50%',
    background: 'var(--accent)',
    animation: 'pulse 2s infinite',
  },

  greeting: {
    fontFamily: 'var(--font-body)',
    fontSize: 20, fontWeight: 300,
    color: 'var(--text2)',
    marginBottom: 6,
  },

  name: {
    fontFamily: 'var(--font-head)',
    fontSize: 'clamp(56px, 8vw, 92px)',
    fontWeight: 800,
    letterSpacing: '-3px',
    lineHeight: 1,
    color: 'var(--text)',
    marginBottom: 16,
  },
  nameAccent: { color: 'var(--accent)' },

  role: {
    fontFamily: 'var(--font-head)',
    fontSize: 'clamp(20px, 3vw, 30px)',
    fontWeight: 500,
    color: 'var(--text2)',
    letterSpacing: '-0.5px',
    marginBottom: 6,
  },

  tagline: {
    fontSize: 12, fontWeight: 600,
    letterSpacing: '0.14em',
    textTransform: 'uppercase',
    color: 'var(--accent)',
    marginBottom: 28,
  },

  desc: {
